// Rust implementation should follow semantic specification
// Use Rust idioms while maintaining mathematical equivalence

use std::f64::consts::LN_2;

pub struct BlockedHRF<T> {
    original_hrf: T,
    width: f64,
    precision: f64,
    half_life: Option<f64>,
    summate: bool,
    normalize: bool,
    span: f64,
    nbasis: usize,
}

impl<T> BlockedHRF<T>
where
    T: HRF,
{
    pub fn new(original_hrf: T, width: f64, precision: f64, 
               half_life: Option<f64>, summate: bool, normalize: bool) -> Self {
        let span = original_hrf.span() + width;
        let nbasis = original_hrf.nbasis();

        BlockedHRF {
            original_hrf,
            width,
            precision,
            half_life,
            summate,
            normalize,
            span,
            nbasis,
        }
    }

    pub fn evaluate(&self, t: f64) -> f64 {
        if self.width == 0.0 {
            return self.original_hrf.evaluate(t);
        }

        let mut result = 0.0;
        let mut max_val = 0.0;
        let mut tau = 0.0;

        while tau <= self.width {
            let eval_time = t - tau;
            if eval_time >= 0.0 {
                let hrf_val = self.original_hrf.evaluate(eval_time);

                // Apply exponential decay if specified
                let decay = if let Some(hl) = self.half_life {
                    (-LN_2 * tau / hl).exp()
                } else {
                    1.0
                };

                let weighted_val = hrf_val * decay;

                if self.summate {
                    result += weighted_val * self.precision;
                } else {
                    max_val = max_val.max(weighted_val);
                }
            }
            tau += self.precision;
        }

        let final_result = if self.summate { result } else { max_val };

        // Normalization would require a separate pass to find the global maximum
        final_result
    }

    pub fn span(&self) -> f64 {
        self.span
    }

    pub fn nbasis(&self) -> usize {
        self.nbasis
    }
}

pub trait HRF {
    fn evaluate(&self, t: f64) -> f64;
    fn span(&self) -> f64;
    fn nbasis(&self) -> usize;
}

pub fn block_hrf<T: HRF>(hrf: T, width: f64, precision: f64, 
                         half_life: Option<f64>, summate: bool, 
                         normalize: bool) -> BlockedHRF<T> {
    BlockedHRF::new(hrf, width, precision, half_life, summate, normalize)
}
